const BASE='https://services.leadconnectorhq.com';
const token=process.env.GHL_PRIVATE_INTEGRATION_TOKEN_TJB||process.env.GHL_PRIVATE_INTEGRATION_TOKEN;
const loc=process.env.GHL_LOCATION_ID_TJB||process.env.GHL_LOCATION_ID||'TW8JsPW5NMnA3tfK2XLn';
const tz='America/Chicago';
if(!token){console.error('missing token');process.exit(1)}
const H={Authorization:`Bearer ${token}`,Version:'2021-07-28','Content-Type':'application/json'};
const dkey=(ms)=>new Intl.DateTimeFormat('en-CA',{timeZone:tz,year:'numeric',month:'2-digit',day:'2-digit'}).format(new Date(ms));
function q(vals,p){if(!vals.length)return null;const s=[...vals].sort((a,b)=>a-b);const i=Math.max(0,Math.min(s.length-1,Math.ceil(p*s.length)-1));return s[i];}
function ms(v){if(v==null)return NaN; if(typeof v==='number') return v<1e12?v*1000:v; const p=Date.parse(v); return Number.isNaN(p)?NaN:p;}
function startOfDayUtcForTZ(dateKey){const [y,m,d]=dateKey.split('-').map(Number);const base=Date.UTC(y,m-1,d,0,0,0,0);for(let off=-14*60;off<=14*60;off+=15){const cand=base-off*60000;const f=new Intl.DateTimeFormat('en-CA',{timeZone:tz,year:'numeric',month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit',second:'2-digit',hourCycle:'h23'});const parts=Object.fromEntries(f.formatToParts(new Date(cand)).map(p=>[p.type,p.value]));if(+parts.year===y&&+parts.month===m&&+parts.day===d&&+parts.hour===0&&+parts.minute===0&&+parts.second===0)return cand;}throw new Error('midnight resolve failed '+dateKey)}
function addDays(k,n){const [y,m,d]=k.split('-').map(Number);const z=new Date(Date.UTC(y,m-1,d+n));return `${z.getUTCFullYear()}-${String(z.getUTCMonth()+1).padStart(2,'0')}-${String(z.getUTCDate()).padStart(2,'0')}`}
async function req(path){const r=await fetch(BASE+path,{headers:H});const t=await r.text();let j={};try{j=t?JSON.parse(t):{}}catch{j={raw:t}};if(!r.ok)throw new Error(path+' -> '+r.status+' '+t.slice(0,160));return j}
(async()=>{
const now=new Date();
const nowKey=dkey(now.getTime());
const yKey=addDays(nowKey,-1);
const yStart=startOfDayUtcForTZ(yKey); const yEnd=startOfDayUtcForTZ(addDays(yKey,1))-1;
const wStartKey=addDays(yKey,-6); const wStart=startOfDayUtcForTZ(wStartKey); const wEnd=yEnd;
const convRes=await req(`/conversations/search?locationId=${loc}&limit=100`); const convs=convRes.conversations||[];
const oppRes=await req(`/opportunities/search?location_id=${loc}&limit=100`); const opps=oppRes.opportunities||[];
let leadsY=0,leadsW=0,bookY=0,bookW=0; const speedY=[],speedW=[]; let stale24=0;
for(const c of convs){
  const added=ms(c.dateAdded); const last=ms(c.lastMessageDate||c.dateUpdated||c.dateAdded);
  if(c.inbox===true && Number.isFinite(last) && (Date.now()-last)>24*3600*1000) stale24++;
  const inW=Number.isFinite(added)&&added>=wStart&&added<=wEnd; const inY=Number.isFinite(added)&&added>=yStart&&added<=yEnd;
  if(inW)leadsW++; if(inY)leadsY++;
  if(!inW) continue;
  let msgs=[]; try{const m=await req(`/conversations/${c.id}/messages?limit=100`); msgs=Array.isArray(m.messages)?m.messages:(Array.isArray(m.data)?m.data:[])}catch{}
  const e=msgs.map(m=>({dir:(m.direction||m.messageDirection||'').toLowerCase(),type:(m.messageType||m.type||'').toLowerCase(),t:ms(m.dateAdded||m.createdAt||m.timestamp||m.messageDate)})).filter(x=>Number.isFinite(x.t)).sort((a,b)=>a.t-b.t);
  if(e.length){
    const fi=e.find(m=>m.dir==='inbound')?.t ?? added; const fo=e.find(m=>m.dir==='outbound')?.t;
    if(Number.isFinite(fi)&&Number.isFinite(fo)&&fo>=fi){const mins=(fo-fi)/60000; if(mins>=0 && mins<20160){speedW.push(mins); if(inY)speedY.push(mins);}}
    const hasW=e.some(m=>(m.type.includes('appointment')||m.type.includes('calendar'))&&m.t>=wStart&&m.t<=wEnd);
    const hasY=e.some(m=>(m.type.includes('appointment')||m.type.includes('calendar'))&&m.t>=yStart&&m.t<=yEnd);
    if(hasW)bookW++; if(hasY)bookY++;
  }
}
const oppMoveY=opps.filter(o=>{const t=ms(o.lastStageChangeAt); return Number.isFinite(t)&&t>=yStart&&t<=yEnd}).length;
const oppMoveW=opps.filter(o=>{const t=ms(o.lastStageChangeAt); return Number.isFinite(t)&&t>=wStart&&t<=wEnd}).length;
console.log(JSON.stringify({window:{yKey,wStartKey},sample:{conversations:convs.length,opportunities:opps.length},yesterday:{bookedCalls:bookY,speedMedianMin:q(speedY,.5),speedP95Min:q(speedY,.95),leadsCreated:leadsY,opportunitiesMovedStages:oppMoveY,staleLeadsOver24h:stale24},trend7d:{bookedCallsTotal:bookW,bookedCallsDailyAvg:bookW/7,speedMedianMin:q(speedW,.5),speedP95Min:q(speedW,.95),leadsCreatedTotal:leadsW,leadsDailyAvg:leadsW/7,opportunitiesMovedStagesTotal:oppMoveW,oppMovesDailyAvg:oppMoveW/7,staleLeadsOver24h:stale24}},null,2));
})().catch(e=>{console.error(String(e));process.exit(1)});
